draw((0,-5)--(0,11),Arrows);
label("$x$",(12,0)); label("$y$",(-1,11));
draw(Circle((2,3),5));
dot((2,3)); dot((-1,-1));
label("(2,3)",(2,3),W);
label("(-1,-1)",(-1,-1),W);
draw((-1,-1)--(2,-1),dashed+red); draw((2,-1)--(2,3),dashed+blue);
